import time

class AuditLog:
    def __init__(self):
        self.logs = []

    def logAction(self, actor, action):
        entry = {"timestamp": time.time(), "actor": actor, "action": action}
        self.logs.append(entry)
        return True

    def getLogs(self, limit=10, offset=0):
        return self.logs[offset:offset+limit]

class ValidatorCouncil:
    def __init__(self):
        self.validators = {} # address -> weight

    def addValidator(self, address, weight=1):
        self.validators[address] = weight
        return True

    def removeValidator(self, address):
        if address in self.validators:
            del self.validators[address]
        return True

    def getValidators(self):
        return self.validators

class MultiSig:
    def __init__(self):
        self.proposals = {} # id -> proposal details

    def propose(self, proposal_id, action_payload, required_sigs):
        if proposal_id not in self.proposals:
            self.proposals[proposal_id] = {
                "payload": action_payload,
                "required": required_sigs,
                "signatures": [],
                "executed": False
            }
        return True

    def approve(self, proposal_id, address_sig):
        if proposal_id in self.proposals:
            prop = self.proposals[proposal_id]
            if address_sig not in prop["signatures"]:
                prop["signatures"].append(address_sig)
        return True

    def execute(self, proposal_id):
        prop = self.proposals.get(proposal_id)
        if prop and len(prop["signatures"]) >= prop["required"] and not prop["executed"]:
            prop["executed"] = True
            return True
        raise Exception("Not ready for execution")

class CertificateAuthority:
    def __init__(self):
        self.certs = {}
        self.revoked = []

    def issueCert(self, cert_id, subject_data):
        self.certs[cert_id] = subject_data
        return True

    def revokeCert(self, cert_id):
        if cert_id not in self.revoked:
            self.revoked.append(cert_id)
        return True

    def verifyCert(self, cert_id):
        return cert_id in self.certs and cert_id not in self.revoked
